const body = $input.first().json.body;

// Support both separate fields and combined "street, city, state, zip" address string
let address = (body.address || '').trim();
let city    = (body.city    || '').trim();
let state   = (body.state   || '').trim();
let zip     = (body.zip     || '').trim();

if (address && (!city || !state || !zip)) {
  const parts = address.split(',').map(p => p.trim());
  if (parts.length >= 4) {
    address = parts[0];
    city    = parts[1];
    state   = parts[2];
    zip     = parts[3];
  } else if (parts.length === 3) {
    // "street, city, state zip"
    address = parts[0];
    city    = parts[1];
    const stateZip = parts[2].split(/\s+/);
    state   = stateZip[0] || '';
    zip     = stateZip[1] || '';
  }
}

// Required fields
const required = { address, city, state, zip };
for (const [f, v] of Object.entries(required)) {
  if (!v) throw new Error(`Missing required field: ${f}`);
}

const full_address = `${address}, ${city}, ${state} ${zip}`;

return [{ json: {
  address,
  city,
  state,
  zip,
  full_address,
  price_range:  body.price_range  || '',
  beds:         body.beds         || null,
  baths:        body.baths        || null,
  sqft:         body.sqft         || null,
  year_built:   body.year_built   || null,
  caller:       body.caller       || 'unknown',
  client_id:    body.client_id    || 'e2f9934c-4d28-4bb4-ac90-4284c1123517'
}}];

const items = $input.all();
const input = $('Prep Input').first().json;

// Check if Postgres returned a valid cached row with a result field
if (
  items.length > 0 &&
  items[0].json &&
  items[0].json.result &&
  !items[0].json.error
) {
  const cached = typeof items[0].json.result === 'string'
    ? JSON.parse(items[0].json.result)
    : items[0].json.result;
  return [{ json: { cache_hit: true, ...cached, _cached: true } }];
}

// Cache miss — pass input forward
return [{ json: { cache_hit: false, ...input } }];

const geocoder = $input.first().json;
const input = $('Prep Input').first().json;

// Check if address validated
const matches = geocoder?.result?.addressMatches || [];
const address_verified = matches.length > 0;
const coords = address_verified ? matches[0].coordinates : null;

const prompt = `Research the following property and local market. Return ONLY information you find from search results — do not estimate or invent any numbers.

PROPERTY: ${input.full_address}
PRICE RANGE: ${input.price_range || 'not specified'}
BEDS: ${input.beds || 'unknown'} | BATHS: ${input.baths || 'unknown'}

Return a JSON object with these exact fields:
- walkability: { description: string } — source from Walk Score or similar, describe in one sentence
- schools: [ { name: string, grades: string, rating: number|null, source: string, distance_miles: number|null } ] — nearest 2-3 public schools from GreatSchools or school district sites
- market: { median_sale_price: number|null, median_days_on_market: number|null, inventory_level: "low"|"balanced"|"high"|null, yoy_price_trend: string|null, data_source: string, data_date: string } — source from Zillow, Redfin, or Realtor.com
- recent_comps: [ { address: string, sold_price: number, sold_date: string, beds: number|null, baths: number|null, sqft: number|null } ] — up to 4 comparable recently sold homes from public listings
- data_confidence: { market: "high"|"medium"|"low", comps: "high"|"medium"|"low", schools: "high"|"medium"|"low" }

CRITICAL: Do not include demographic data, crime statistics, or any information about the racial or ethnic composition of the area. Do not invent or estimate any data — if you cannot find it, return null.`;

const geminiBody = {
  contents: [{ parts: [{ text: prompt }] }],
  tools: [{ google_search: {} }],
  generation_config: {}
};

return [{ json: { ...input, address_verified, coords, geminiBody } }];

const geminiResponse = $input.first().json;
const input = $('Build Gemini Prompt').first().json;

// Parse Gemini response
let research = {};
try {
  const candidates = geminiResponse.candidates;
  if (candidates && candidates[0] && candidates[0].content && candidates[0].content.parts) {
    let text = candidates[0].content.parts[0].text;
    // Strip markdown code fences if Gemini wrapped the JSON
    text = text.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
    research = JSON.parse(text);
  }
} catch(e) {
  research = { parse_error: String(e.message) };
}

// Compliance filter — strip any field containing blocked keywords
const BLOCKED = ['demographic', 'crime', 'race', 'racial', 'ethnicity', 'religion', 'national_origin', 'segregat'];
function stripBlocked(obj) {
  if (typeof obj !== 'object' || obj === null) return obj;
  if (Array.isArray(obj)) return obj.map(stripBlocked);
  const clean = {};
  for (const [k, v] of Object.entries(obj)) {
    if (BLOCKED.some(b => k.toLowerCase().includes(b))) continue;
    if (typeof v === 'string' && BLOCKED.some(b => v.toLowerCase().includes(b))) continue;
    clean[k] = stripBlocked(v);
  }
  return clean;
}

const cleaned = stripBlocked(research);

return [{ json: { ...input, research: cleaned } }];

