const claudeResponse = $input.first().json;
const prev = $('Parse + Compliance Filter').first().json;
const research = prev.research || {};

// Extract insight_block from Claude JSON response
let insight_block = '';
try {
  // Strip markdown code fences if Claude wrapped the JSON
  let text = claudeResponse.content[0].text.trim().replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
  const parsed = JSON.parse(text);
  insight_block = parsed.insight_block || '';
} catch(e) {
  // Claude returned plain text — strip any stray fences and use as-is
  insight_block = (claudeResponse.content[0].text || '').trim().replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
}

const hasComps = Array.isArray(research.recent_comps) && research.recent_comps.length > 0;

const output = {
  status: 'ok',
  address_verified: prev.address_verified || false,
  walkability:      research.walkability      || null,
  schools:          research.schools          || [],
  market:           research.market           || null,
  recent_comps:     research.recent_comps     || [],
  data_confidence:  research.data_confidence  || { market: 'low', comps: 'low', schools: 'low' },
  insight_block,
  comps_disclaimer: hasComps
    ? 'Comparable sales sourced from publicly available listings. For a complete market analysis, see your agent\'s formal CMA.'
    : undefined
};

// Remove undefined keys so the response JSON is clean
Object.keys(output).forEach(k => { if (output[k] === undefined) delete output[k]; });

return [{ json: output }];
